import type { Metadata } from "next";

export const metadata: Metadata = {
  title: "Docs Portal",
  description: "Deterministic app-router fixture for route intelligence.",
};

export default function RootLayout({ children }: { readonly children: React.ReactNode }) {
  return (
    <html lang="en">
      <body>{children}</body>
    </html>
  );
}

import { DashboardSummary } from "../components/dashboard-summary";
import { getFeaturedDocs } from "../lib/content";

export default function HomePage() {
  return (
    <main>
      <DashboardSummary docs={getFeaturedDocs()} />
    </main>
  );
}

import { getDocBySlug, getDocSlugs } from "../../../lib/content";

export function generateStaticParams() {
  return getDocSlugs().map((slug) => ({ slug }));
}

export default function DocPage({ params }: { readonly params: { readonly slug: string } }) {
  const doc = getDocBySlug(params.slug);
  return <article>{doc.title}</article>;
}

import { healthSummary } from "../../../lib/health";

export function GET(): Response {
  return Response.json(healthSummary());
}

import { expect, it } from "vitest";
import { GET } from "./route";

it("returns health", () => {
  expect(GET()).toBeInstanceOf(Response);
});

export default function sitemap() {
  return [{ url: "https://example.test/" }];
}

export default function robots() {
  return { rules: [{ userAgent: "*", allow: "/" }] };
}

export function DashboardSummary({ docs }: { readonly docs: Array<{ readonly title: string }> }) {
  return (
    <section>
      {docs.map((doc) => (
        <h2 key={doc.title}>{doc.title}</h2>
      ))}
    </section>
  );
}

const docs = [{ slug: "intro", title: "Intro" }];

export function getFeaturedDocs() {
  return docs;
}

export function getDocSlugs() {
  return docs.map((doc) => doc.slug);
}

export function getDocBySlug(slug: string) {
  return docs.find((doc) => doc.slug === slug) ?? docs[0];
}

export function healthSummary() {
  return { ok: true, service: "docs" };
}
